rule.example:

class ClassName
{
    public void get_name() { }   // violation
    public void GetName() { }    // OK
}


class ClassName
{
    private int bad_field;    // violation
    private int _goodField;   // OK (allowUnderscorePrefix=true)
    public int GoodProp { get; set; }  // OK
}


class ClassName
{
    public void DoSomething(string user_name) { }   // violation
    public void DoSomething(string userName) { }    // OK
}


class ClassName
{
    public void DoSomething()
    {
        var data_module = new DataModule();   // violation
        var dataModule = new DataModule();    // OK
    }
}
